class Solution:
    def countGoodArrays(self, n, m, k):
        MOD = 10 ** 9 + 7
        if n == 1:
            return m % MOD if k == 0 else 0
        arrs = [[v] for v in range(1, m + 1)]
        for _ in range(n - 1):
            arrs = [a + [v] for a in arrs for v in range(1, m + 1)]
        count = 0
        for a in arrs:
            matches = sum(1 for i in range(1, len(a)) if a[i - 1] == a[i])
            if matches == k:
                count += 1
        return count % MOD

