var countGoodArrays = function(n, m, k) {
    const MOD = 1000000007n;
    function power(base, exp, mod) {
        base = ((base % mod) + mod) % mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }
    const maxN = Math.max(n, 1);
    const fact = new Array(maxN + 1);
    fact[0] = 1n;
    for (let i = 1; i <= maxN; i++) fact[i] = (fact[i - 1] * BigInt(i)) % MOD;
    const invFact = new Array(maxN + 1);
    invFact[maxN] = power(fact[maxN], MOD - 2n, MOD);
    for (let i = maxN; i > 0; i--) invFact[i - 1] = (invFact[i] * BigInt(i)) % MOD;
    function comb(a, b) {
        if (b < 0 || b > a) return 0n;
        return (fact[a] * invFact[b] % MOD) * invFact[a - b] % MOD;
    }
    const c = comb(n - 1, k);
    const base = BigInt(m - 1);
    const exp = BigInt(n - 1 - k);
    let p;
    if (base === 0n && exp === 0n) p = 1n;
    else p = power(base, exp, MOD);
    const ans = (c * BigInt(m) % MOD) * p % MOD;
    return Number(ans);
};
